import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"G05 營收模式 — 力成科技 (6239)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/6239_力成/20260617/G05_營收模式.md","filePath":"審計報告庫/經營審計/6239_力成/20260617/G05_營收模式.md"}'),r={name:"審計報告庫/經營審計/6239_力成/20260617/G05_營收模式.md"};function n(d,t,s,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="g05-營收模式-—-力成科技-6239" tabindex="-1">G05 營收模式 — 力成科技 (6239) <a class="header-anchor" href="#g05-營收模式-—-力成科技-6239" aria-label="Permalink to &quot;G05 營收模式 — 力成科技 (6239)&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>檢視力成科技的營收結構與商業模式，包含服務類別佔比、客戶集中度、定價策略與營收成長動能。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>純OSAT模式，收入全來自封裝測試代工。邏輯產品佔比從30%升至43%，AI/HPC驅動下2026年營收預估900-940億元，成長強勁。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>純OSAT模式，2026年Q1封裝67%、測試22%、SiP/模組11%。2026年1-5月營收368.5億元（YoY+35-40%），5月79.18億元創高峰。前三大客戶（金士頓、美光、鎧俠）集中度55-60%。營收穩健成長，記憶體週期為天然風險。（數據來源：FinMind月營收、Fugle法說會）</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p>力成科技的營運模式與營收結構分析如下：</p><p><strong>一、商業模式</strong> 力成的OSAT模式收取封裝/測試服務費用（Assembly &amp; Test Service Fee），不銷售品牌產品。與晶圓代工（台積電）與記憶體原廠（美光、金士頓、鎧俠）合作，承接後段封測業務。營收認列方式為勞務收入（服務完成時認列）。</p><p><strong>二、月營收趨勢</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">月份</th><th style="text-align:left;">營收(億元)</th><th style="text-align:left;">趨勢</th></tr></thead><tbody><tr><td style="text-align:left;">2025/06</td><td style="text-align:left;">62.6</td><td style="text-align:left;">谷底後復甦</td></tr><tr><td style="text-align:left;">2025/09</td><td style="text-align:left;">67.0</td><td style="text-align:left;">逐步加溫</td></tr><tr><td style="text-align:left;">2025/12</td><td style="text-align:left;">73.0</td><td style="text-align:left;">Q4旺季</td></tr><tr><td style="text-align:left;">2026/01</td><td style="text-align:left;">72.4</td><td style="text-align:left;">持平</td></tr><tr><td style="text-align:left;">2026/02</td><td style="text-align:left;">67.0</td><td style="text-align:left;">工作天數少</td></tr><tr><td style="text-align:left;">2026/03</td><td style="text-align:left;">73.7</td><td style="text-align:left;">回溫</td></tr><tr><td style="text-align:left;">2026/04</td><td style="text-align:left;">75.8</td><td style="text-align:left;">持續成長</td></tr><tr><td style="text-align:left;">2026/05</td><td style="text-align:left;">79.2</td><td style="text-align:left;">歷史高峰區</td></tr></tbody></table><p>近12個月累計營收844.47億元，已超越2025全年749.29億元。2026年預估全年營收900-940億元（FactSet中位數940.64億元）。</p><p><strong>三、客戶結構</strong></p><ul><li>金士頓：最大股東（持股約15-20%），長期合約，貢獻營收約25-30%</li><li>美光：五年LTA，保障DRAM封測產能50%，佔營收約20-25%</li><li>鎧俠（東芝記憶體）：NAND Flash封測，佔約10-15%</li><li>其他：NVIDIA（AI晶片封測）、Bosch/Continental（車用）、國內IC設計公司</li></ul><p>客戶集中度偏高（前三大約55-60%），但主要客戶均為全球記憶體與半導體龍頭，穩定性高。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>🔴 空方觀點（利空風險）</strong></p><ol><li><strong>記憶體週期性風險</strong>：力成營收高度連動記憶體景氣，2024-2025年記憶體價格波動導致營收成長放緩（2025全年僅年增2.2%）。若2026年下半年記憶體庫存調整，力成營收成長可能受影響。</li><li><strong>客戶集中度偏高</strong>：前三大客戶（金士頓、美光、鎧俠）佔營收約55-60%，任何單一客戶訂單轉移或自建封測產能都將對營收造成顯著衝擊。美光已逐步收回西安廠自營，顯示客戶垂直整合的潛在威脅。</li></ol><p><strong>🟢 多方觀點（機會可能性）</strong></p><ol><li><strong>漲價效應持續發酵</strong>：封裝產能接近滿載、測試產能約85%，供需吃緊下力成已啟動部分產品漲價。Q1毛利率年增2.3個百分點至19.4%，反映價格調整效益逐步顯現。若產能持續緊俏，2026年毛利率有機會站上20%。</li><li><strong>邏輯產品佔比提升擴張營收堡壘</strong>：邏輯IC封測（尤其是AI晶片）單價與毛利率均高於記憶體封測。邏輯佔比從30%→43%的結構轉型，將使力成的營收曲線更平滑，降低對單一記憶體週期的依賴性。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind：TaiwanStockRevenue（2025/06 - 2026/05月營收）</li><li>web_search：力成 6239 營收結構 2025 2026（Fugle、PitchBook、ResearchAndMarkets）</li><li>web_search：力成 6239 客戶 供應商（CMoney分析）</li><li>經濟日報：力成2025年Q4財報報導</li></ul>',23)])])}const c=e(r,[["render",n]]);export{x as __pageData,c as default};
